                 (id INTEGER PRIMARY KEY, name TEXT, price REAL, business_id INTEGER, FOREIGN KEY (business_id) REFERENCES Businesses(id))''')
    c.execute('''CREATE TABLE IF NOT EXISTS Customers
                 (id INTEGER PRIMARY KEY, name TEXT, email TEXT, address TEXT)''')

